diff --git a/absl/synchronization/blocking_counter.cc b/absl/synchronization/blocking_counter.cc
+bool BlockingCounter::WaitWithTimeout(absl::Duration timeout) {
+  base_internal::TraceWait(this, TraceObjectKind());
+  bool done;
+  {
+    MutexLock l(this->lock_);
+    ABSL_RAW_CHECK(num_waiting_ == 0, "multiple threads called Wait()");
+    num_waiting_++;
+    done = this->lock_.AwaitWithTimeout(Condition(IsDone, &this->done_), timeout);
+  }
+  base_internal::TraceContinue(done ? this : nullptr, TraceObjectKind());
+  return done;
+}
diff --git a/absl/synchronization/blocking_counter.h b/absl/synchronization/blocking_counter.h
+  bool WaitWithTimeout(absl::Duration timeout);
